queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?toolname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTools ?child ; p:hasCinematographers ?parent . } GROUP BY ?child }
  ?child p:toolName ?toolname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Cinematographers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?toolname WHERE {
  ?cinematographers_tools a :Cinematographers_Tools .
  ?tools a :Tools .
  ?cinematographers_tools p:hasTools ?tools .
  ?cinematographers a :Cinematographers .
  ?cinematographers_tools p:hasCinematographers ?cinematographers .
  ?cinematographers p:name ?name .
  ?tools p:toolName ?toolname .
} }
  collective: { SELECT ?toolname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTools ?child ; p:hasCinematographers ?parent . } GROUP BY ?child }
  ?child p:toolName ?toolname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Cinematographers } }
  FILTER(?nf = ?total)
} }
}
